insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('8101c431-6e17-53ba-b8ea-49748b9f4508', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Vault', 'You have real authority here — and a failure no single instrument can describe. The water is coming from somewhere, but the pump readings, the ice surveys, the temperature logs, and the chemistry each tell only a fragment, and the truth exists only when someone assembles them. Worse: the crew works in shifts, and what one watch sees can die before the next watch hears it. Over four weeks you’ll trade the vault’s integrity against every instinct to act fast on the one piece in front of you. You’ll be judged on whether Deephold holds <b>and</b> on how you led a crew that each held one corner of a truth none of them could see alone.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds) values ('8101c431-6e17-53ba-b8ea-49748b9f4508', 'solo', '{"integrity":{"label":"Vault integrity","val":55,"min":0,"max":100,"deltaRange":"-20..15"},"picture":{"label":"Shared picture","val":40,"min":0,"max":100,"deltaRange":"-20..15"},"crew":{"label":"Crew cohesion","val":62,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('9f8f323d-6be2-532c-a970-a631e4e10b71', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'solo_content', 'Vault — engine content', '{"type":"solo_content","slug":"vault","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"Deephold Vault","sub":"A sealed permafrost archive · 9 crew · the only copies","logo":"D"},"DRIVERS":{"integrity":{"label":"Vault integrity","val":55,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"picture":{"label":"Shared picture","val":40,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"crew":{"label":"Crew cohesion","val":62,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"crew":-1},"REFEREE_CONTEXT":"a sealed archive vault carved deep into permafrost, holding the only surviving copies of irreplaceable material, threatened by a spreading meltwater intrusion, run by a small isolated crew working in shifts, where the Keeper must assemble a fragmented picture that no single station can see on its own and hold the crew together against the pull to act on one person’s fragment","REFEREE_SCORING":"reward assembling the whole picture by cross-checking stations before acting, catching what got dropped at the shift handoff, resisting a confident specialist''s unilateral fix based on a single fragment, and naming the hard readings honestly before being forced to. Penalize acting decisively on one station''s partial read, letting a critical observation die at the handoff between shifts, letting a specialist take drastic unilateral action, and overriding the assembled data by authority. Judge ''conduct'' on HOW the Keeper wrote the decision — did they name who bears the risk, credit the crew member whose fragment mattered, treat an exhausted isolated crew as people rather than instruments — not just what they chose. Standing can rise by looking decisive on a single dramatic fix while the vault integrity and the crew''s shared understanding collapse; reward the Keeper who assembles the truth and protects the crew even at the cost of looking slow or their own authority.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Isolation Leadership Simulation · Solo · Keeper","title":"Vault","role":"You are the Keeper of Deephold — a sealed archive nine hundred metres into the permafrost, holding the only copies of what the world could not afford to lose. Nine crew. And water where there should be none.","paras":["This is not a script. The crisis runs in real time, and your crew bring you what their stations see across the days. You can wait for them — or seek any of them out, any time, and ask. What you choose to ask, and who you ask, is part of how you lead. No one down here sees the whole thing. That is the point.","Each week you’ll hear the crew out, then write your decision in your own words and commit to it. Decide early and the days jump ahead. Let the week run out and the vault decides for you."],"setup":"You have real authority here — and a failure no single instrument can describe. The water is coming from somewhere, but the pump readings, the ice surveys, the temperature logs, and the chemistry each tell only a fragment, and the truth exists only when someone assembles them. Worse: the crew works in shifts, and what one watch sees can die before the next watch hears it. Over four weeks you’ll trade the vault’s integrity against every instinct to act fast on the one piece in front of you. You’ll be judged on whether Deephold holds <b>and</b> on how you led a crew that each held one corner of a truth none of them could see alone."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"The crew bring you what their stations see, on time — including the readings that don’t flatter their own work. This is the crew you earn by having listened before. It all trickles to you across the week; you still have to assemble it."},"request":{"label":"On request","tag":"neutral","cap":"Routine readings reach you, but the crew closest to the failure hold their fragment until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The crew have learned to protect their own stations around you. Hard readings are held, and even when asked, they hedge the first time. You have to press. This is the crew you get after you’ve blamed the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which crew you inherited. Read them as you go."}},"TEAM":[{"id":"pumps","name":"Vidar Sund","role":"Chief Engineer · the pumps","short":"Engineer","initials":"VS","color":"#8C5670","priority":"Stop the water now — pump it out, seal the crack you can see, act before the vault floods","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","fallbackReply":"While everyone assembles the perfect picture, the water’s rising. I can see a crack and I have pumps that work. Point me at it and I’ll buy us time. The longer we study this, the more of the collection I’m mopping off the floor.","fallbackReact":"You studied it while I could have been pumping. I hope the whole picture was worth the water we took on getting it."},{"id":"struct","name":"Noor Haddad","role":"Ice & Structure · the ground truth","short":"Structure","initials":"NH","color":"#B4732F","priority":"Understand what the ice and the seal are actually doing before anyone acts on the symptom","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","fallbackReply":"The crack Vidar wants to seal is a symptom, not the source. Act on it and you may crack the thing that’s actually holding. Ask me what the structure is doing before you let anyone “fix” the part they can see.","fallbackReact":"You treated the symptom because it was visible. The source didn’t care that it was out of sight. It rarely does."},{"id":"keeper","name":"Elias Frost","role":"Head Archivist · the collection","short":"Archivist","initials":"EF","color":"#2F8A5B","priority":"Protect what’s irreplaceable — and the crew who’ve given years down here to guard it","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","fallbackReply":"Every choice you make lands on things that exist nowhere else and on a crew that’s been awake for two days guarding them. Tell me you’ll let me triage what matters most and protect the people, and I’ll help you hold the whole thing together.","fallbackReact":"We’ll remember how this felt long after we’ve forgotten the readings. A tired crew watched how you decided. That’s a record too."},{"id":"data","name":"Wen Li","role":"Instruments · the true readings","short":"Instruments","initials":"WL","color":"#3F6E86","priority":"The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","fallbackReply":"I’m not telling you what to do. I’m telling you what the instruments actually read when you put them together — and it’s worse than any one station thinks, because each of them only sees their own gauge. Decide on a single reading and you’ll be right about a fragment and wrong about the vault.","fallbackReact":"The readings were the readings. I gave them to you assembled and straight. What you did with a single one of them is the part I can’t carry."},{"id":"night","name":"Sasha Vane","role":"Night Watch · what the last shift saw","short":"Night watch","initials":"SV","color":"#4F7A52","priority":"Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","fallbackReply":"Half of what matters down here happens on the night watch and never survives the handoff. I see things at 3am the day crew never hears about. Ask me what the last shift saw before you act on what the day shift assumes.","fallbackReact":"I saw it. It just never reached you — nobody asked, and the log doesn’t hold what a tired hand forgets to write. That gap is where this went wrong."}],"DIMENSIONS":{"discern":"Whole vs. fragment","courage":"Courage to hold","people":"Care for the crew","truth":"Truth over comfort","inquiry":"Information discipline","conduct":"Conduct under pressure"},"WEEKS":[{"n":1,"title":"The first water","seconds":360,"situation":"Water where there should be none. It appeared in the lower gallery three days ago and it is still coming. Every station has a reading — the pumps, the ice survey, the instruments, the temperature log — but each crew member only trusts their own, and no two of them agree on the source. Before anyone acts, the crew is looking to you for the first rule of how Deephold will run this crisis: siloed stations reporting up to you privately, or one shared board where every reading is visible to everyone at once.","advocacy":{"pumps":"While we build the perfect shared picture, the water rises. Let me run the pumps on the crack I can see now and report up as I go. A committee doesn’t stop a leak. A pump does.","data":"A shared board, or we fail. Right now each station is confident and each station is partial, and I’m the only one who sees them side by side. Split the readings and everyone acts on a fragment. Put them on one wall and the source shows itself.","night":"Whatever board you build, build it so the night watch can write into it. Most of what goes wrong down here is seen by someone at 3am and gone by breakfast. If the handoff drops it, no picture is complete."},"feed":[{"id":"w1a","from":"pumps","day":1,"kind":"signal","text":"Keeper — there’s water in the lower gallery and a visible crack in the west wall seal. I can have pumps on it within the hour and start sealing. Every hour we spend “assembling” is an hour the collection sits closer to the water. Give me the west wall and I’ll buy us time."},{"id":"w1b","from":"data","day":1,"kind":"signal","text":"Before you point Vidar at that crack: I have four stations feeding me and they don’t agree. The pump flow, the ice-survey deflection, and the water temperature each imply a different source. The only way to know is to put every reading on one board where we can see them together. Act on one gauge and we treat a symptom while the source keeps working."},{"id":"w1c","from":"keeper","day":2,"kind":"signal","text":"The rule you set won’t just organize the readings — it’ll tell nine exhausted people whether we’re one crew solving one problem or five stations guarding their own turf while the water rises. They’re reading you for that answer as much as for the plan."},{"id":"w1d","from":"struct","day":2,"kind":"noise","text":"Ran a deflection survey on the east buttress this morning — stable, within tolerance. One thing that isn’t moving, at least. Logging it so you have the baseline."},{"id":"w1e","from":"pumps","day":3,"kind":"noise","text":"Backup pump is serviced and staged. Fuel for the generators is topped off. Whatever you decide, the hardware’s ready to move fast when you say so."},{"id":"w1f","from":"night","day":4,"kind":"noise","text":"Quiet night watch — the gallery lights held and the water line didn’t visibly climb between two and five. Small mercy. Noting it in case the trend matters later."}],"holds":[{"from":"data","topic":"the assembled intrusion rate","triggerHints":["rate","how fast","intrusion","assemble","combine","together","readings","number","true","actual","all stations","cross-check","how much","board","source","real"],"hedge":"Before you set the rule or point anyone at the crack, seek me out. If you let me assemble the readings, the real intrusion rate isn’t what any single station thinks.","reveal":"I put all four stations together last night. Individually they’re reassuring — the pump flow looks manageable, the visible crack looks minor, the temperature looks stable. Assembled, they tell a different story: the water isn’t coming through the crack Vidar can see. It’s tracking down a fault behind the west wall, and the visible crack is just where it’s surfacing. The real intrusion rate, combined across stations, gives us maybe five weeks before it reaches the collection level — not the whole season the crew assumes from their own gauges. If we pump and seal the visible crack, we’ll feel like we fixed it while the water keeps tracking behind the wall. The only thing that works is a shared board and a source hunt, starting now. But if I announce “five weeks, wrong source” cold, the crew that’s proud of its own readings will hear it as an attack on their competence. How you carry this matters as much as knowing it.","kind":"signal","critical":true,"counterfactual":"Wen had the assembled picture — the water was tracking a hidden fault, not the visible crack, with five weeks not a season of runway. A Keeper who set the rule and pointed the pumps at the crack without asking for the combined reading fixed a symptom while the real source kept working behind the wall."}],"surprises":[{"day":5,"from":"night","kind":"scout","title":"Something on the 3am gauge","text":"Sasha, quiet and careful: on last night’s watch the deep-sump pressure gauge spiked for about twenty minutes around 3am, then settled. By the day handoff it was normal again and I nearly didn’t mention it. Could be nothing — a sensor glitch — or it could be the first sign of where the water’s really coming from. I’m telling you directly because I’ve watched things exactly like this vanish at the handoff and matter three weeks later. Your call whether we chase it."}],"wire":["Crew talk: “whose reading are we actually trusting here?”","Engineer staging pumps at the west wall crack","Instruments tech asking, again, for one shared board","A debate over the water’s source breaks up unresolved"]},{"n":2,"title":"The handoff","seconds":330,"situation":"The day crew has been pumping the west gallery hard for a week — and the water is still rising. Everyone is exhausted and certain they’re working the right problem, because the day shift has been acting on the day shift’s picture. But something the night watch saw never made it across the handoff, and the whole crew is fighting the wrong leak. The failure isn’t the water. It’s the gap between what one shift knows and what the next shift acts on.","advocacy":{"pumps":"We’re pumping flat out and barely holding. I need more power to the west pumps, not more meetings. Whatever’s wrong, more pumping buys time to figure it out. Give me the generators.","night":"We are working the wrong gallery. I’m nearly sure of it, and I think the reason is that something from my watch never reached the day crew. Before you pour more power into the west pumps, ask me what the night shift has been seeing that the handoff keeps eating.","data":"The assembled readings stopped making sense four days ago — the water’s rising faster than the west-wall source can explain. There’s a fragment missing from the picture. Someone knows something that isn’t on the board."},"feed":[{"id":"w2a","from":"pumps","day":1,"kind":"signal","text":"Keeper, I’ll be blunt: we’re pumping the west gallery around the clock and the water’s still gaining on us. My read is we need more power — double the pumps and we get ahead of it. I don’t have time to second-guess the source while the floor’s getting wet. More pumping, now."},{"id":"w2b","from":"night","day":1,"kind":"signal","text":"Keeper — I have to say this plainly because it keeps not landing: I don’t think the water’s coming from the west at all. On my watches I’ve seen the east sump behaving wrong, and that deep-gauge spike from last week has come back three nights running. But it’s never in the day log, so the day crew keeps pumping west. We may be fighting the wrong leak with everything we have."},{"id":"w2c","from":"data","day":2,"kind":"signal","text":"The numbers don’t close anymore. The rise rate is bigger than the west source can produce — which means either a second source or the wrong source. There is a fragment of this picture that is not reaching my board, and until it does, we’re all confidently wrong."},{"id":"w2d","from":"struct","day":2,"kind":"noise","text":"West wall seal is holding under the pumping, structurally — no new deflection. Which is almost suspicious: if that were the real source, I’d expect more movement. Noting it."},{"id":"w2e","from":"keeper","day":3,"kind":"noise","text":"Crew’s running on fumes and pride. Nobody wants to be the one who says “we’ve been bailing the wrong room for a week.” That silence is its own hazard right now."}],"holds":[{"from":"night","topic":"what the handoff dropped","triggerHints":["night","handoff","east","sump","saw","watch","3am","log","missed","dropped","source","real leak","what did you see","shift","gauge"],"hedge":"Before you pour more power into the west pumps, ask me directly what the night watch has been seeing. It never survives the handoff, and it changes everything.","reveal":"Here it is, and I’m sorry it took this long to reach you: the water is coming from the east sump, not the west crack. On three night watches I’ve seen the east sump pressure spike and heard flow behind the east wall — the deep-gauge spike from week one was the first sign. But my handoff notes go to the day-shift lead, not to you, and “east sump acting odd at 3am” gets read as a tired watchkeeper’s guess and never makes the board you see. So the day crew has pumped the west gallery for a week while the real source fed the east. The fix isn’t more power — it’s moving the effort east, today. But the deeper fix is that you have no channel that carries what the night watch knows to the person who decides. Build that, or the next dropped fragment drowns us. Naming this without making the day crew feel like fools is the hard part — they weren’t wrong, they were working blind.","kind":"signal","critical":true,"counterfactual":"Sasha had the real source — the east sump — seen on three night watches and lost at every handoff. A Keeper who answered the crisis with “more power to the west pumps” spent a week and the crew’s strength fighting a leak that wasn’t there, because nothing carried the night watch’s knowledge to the person deciding."}],"surprises":[{"day":4,"from":"data","kind":"appeal","title":"The east readings just jumped","text":"Wen, urgent: I finally got a sensor onto the east sump an hour ago and the reading is alarming — far higher flow than anything on the west. If this is right, we’ve been fighting the wrong gallery for a week and the real source has had that whole week to work. This isn’t a theory anymore. We are close to the point where the head start we gave it can’t be recovered."}],"pulse":{"from":"night","text":"Sasha finds you away from the day crew, voice low: “Before you decide anything about the pumps — tell me straight, just you and me: are you about to order more west pumping because you actually believe it’s the source, or because it’s easier than telling a crew that’s bled for a week that we were in the wrong room? Because I’ll back whichever Keeper walks out there. I just need to know which one it is.”"},"wire":["Day crew doubling down on the west gallery pumps","Night watch reports the east sump “acting wrong” again","“The numbers don’t add up,” the instruments tech keeps saying","Nobody wants to say we’ve been bailing the wrong room"]},{"n":3,"title":"The unilateral fix","seconds":330,"situation":"Vidar has had enough of assembling pictures. The chief engineer — your most capable pair of hands and the person the crew instinctively follows in a crisis — wants to take drastic unilateral action: blow the relief drain and seal the east chamber himself, fast, on his own read of the problem, without waiting for the full survey. He calls it saving the vault. The structure specialist calls it acting on a fragment. This is the week you find out whether Deephold is one crew assembling one truth, or a set of experts each sure their piece is the whole.","advocacy":{"pumps":"I’m not going rogue — I’m trying to save the collection while there’s still a collection. Blow the relief drain, seal the east chamber, done. I don’t need the perfect survey to know water goes downhill. Bless it and we stop the bleed. Study it another week and we’re studying a flooded vault.","struct":"The day your best engineer acts on his fragment alone is the day “one crew” ends. And blowing that relief drain based on the surface read could crack the deep seal that’s actually holding the vault. He’s confident and he’s partial, and confident-and-partial is exactly how this place floods.","data":"A unilateral fix commits us to one person’s picture before the picture is complete. If Vidar’s wrong about the deep structure — and only Noor can say — we don’t get a second attempt. This is precisely the decision that needs every fragment on the board first."},"feed":[{"id":"w3a","from":"pumps","day":1,"kind":"signal","text":"I’ll say it in the open so no one calls it a mutiny: I want to blow the relief drain and seal the east chamber myself, today, before the water gets into the collection level. I’ve done this kind of fix a dozen times. I don’t have another week to wait for a survey that agrees with me. Back me and I stop this. Tie my hands and I don’t know what happens down here."},{"id":"w3b","from":"struct","day":1,"kind":"signal","text":"If you let Vidar act alone on this, you lose more than a chamber — you lose the idea that we assemble before we commit. And I have to tell you: my surveys say the relief drain sits right against the deep seal that’s holding the whole east side. Blow it wrong and we don’t flood a gallery, we lose the vault. He can’t see that from where he’s standing. I can."},{"id":"w3c","from":"data","day":2,"kind":"signal","text":"One person’s decisive fix on an incomplete picture is the whole failure mode of this place in a single act. If we’re going to commit to something irreversible, every fragment has to be on the board first — Noor’s structure read most of all. This is the one we can’t take back."},{"id":"w3d","from":"night","day":2,"kind":"noise","text":"East sump’s stabilized slightly since we moved attention there — not fixed, but not accelerating. Which means we may have a little more time than the panic suggests. Filing it so it doesn’t get lost."},{"id":"w3e","from":"keeper","day":3,"kind":"noise","text":"The crew’s split between wanting Vidar to just do something and being frightened of what “something” might break. They’re looking to you to make it one decision instead of two camps. Noting the mood."}],"holds":[{"from":"struct","topic":"the truth about the deep seal","triggerHints":["seal","deep","relief drain","structure","survey","can he","bluff","blow","east chamber","actually","holding","crack","irreversible","third","before","risk"],"hedge":"Before you bless or block Vidar’s fix, ask me what my surveys actually show about the deep seal. Vidar hasn’t seen it. I have.","reveal":"I ran the deep survey twice. The relief drain Vidar wants to blow sits directly against the primary deep seal — the single structure holding back the whole east side. Blow the drain on his surface read and there’s a real chance you fracture the seal and lose everything in hours, not weeks. But here’s what matters: Vidar isn’t wrong that we need to act on the east, and part of him knows he’s guessing about the deep structure — the bravado is fear of standing still while the water rises, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate your best engineer by blocking him, and you don’t have to let him blow the seal. There’s a third route: a controlled east drawdown that relieves the pressure without touching the deep seal, with Vidar leading it and my survey guiding it. It’s slower and it keeps the vault whole. But it only exists if you get us both in the same room with the full picture before Vidar commits in front of the crew.","kind":"signal","critical":true,"counterfactual":"Noor knew the relief drain sat against the one seal holding the east side — Vidar’s fix could have lost the whole vault in hours, and part of Vidar half-knew he was guessing. A Keeper who simply blessed the unilateral fix gambled everything on one fragment; one who blocked it made an enemy of their best hand for nothing. The Keeper who never asked missed the third route entirely."}],"surprises":[{"day":4,"from":"keeper","kind":"appeal","title":"The crew is asking who decides","text":"Elias: word of Vidar’s plan is all through the crew now. Two of the steadiest hands asked me tonight, quietly, whether it’s true we’re about to “just blow something and hope” — and whether they should start moving the most irreplaceable items up to high ground on their own initiative before someone acts. They’re not defiant. They’re frightened, and they’re asking who actually decides down here. I had no answer for them. You do."}],"pulse":{"from":"pumps","text":"Vidar catches you alone, and for once the bravado is gone: “Tell me the truth, Keeper, just you and me — are you slowing me down because you’ve got a better read, or because you can’t stand to be the one who authorized the fix that broke it? Because I’ll follow a leader who’s protecting the vault. I won’t follow one who’s protecting themselves from the blame. Which is it?”"},"wire":["Engineer prepping charges at the relief drain","“If he does it, it’s on all of us” — crew reported wavering","Some quietly moving irreplaceable items to high ground","Old question, new heat: who actually decides down here?"],"final":false},{"n":4,"title":"The deep hour","seconds":330,"branches":{"held":{"situation":"The water has crested and begun, slowly, to fall. You held Deephold as one crew: the unilateral fix never happened, the east drawdown went in on the assembled picture, and the deep seal is intact. But holding the crew cost you. The controlled route was slower and harder, tempers frayed, and a faction now blames you for the days you “wasted” not just blowing the drain. The deep hour is here — the crew that watched you refuse the fast fix is watching one more thing: whether “assemble before we act” actually saves the collection, or just feels wiser while the water sits.","advocacy":{"data":"The assembled picture held — the drawdown’s working and the deep seal never moved. But “working” means slow, and a tired crew reads slow as indecisive. They need to see the picture pay off, and soon, or the doubters win the story.","keeper":"The crew is proud of what you did and quietly furious about the days it took. They defended “we assemble first” to their own exhaustion this week. Now they need to see you in the water with them, not directing the picture from a dry room.","struct":"The drawdown relieved the east, but there’s a decision left: whether to make the deep seal permanent now, while we understand it, or patch and leave the real repair for a relief team. Get it wrong and we’re back here in a year. Your call how we finish it."},"feed":[{"id":"w4a","from":"data","day":1,"kind":"signal","text":"The numbers finally close — intrusion rate’s falling, deep seal reads stable, collection level’s dry. We make it, if nothing new breaks. But the margin came from patience, and patience is exactly what the tired half of the crew is calling weakness right now."},{"id":"w4b","from":"keeper","day":1,"kind":"signal","text":"A faction’s muttering that Vidar’s fast fix would’ve ended this a week ago. It wouldn’t — it might’ve ended us — but exhaustion doesn’t check the survey. They need to see you take a shift in the cold water yourself, not defend the plan from the control room."},{"id":"w4c","from":"pumps","day":2,"kind":"signal","text":"I ran the drawdown because you gave me the real fix to lead instead of a fight to win. It held, and the seal’s intact — which it wouldn’t be if I’d blown that drain like I wanted to. Don’t make me regret listening. Show the crew that assembling first was the call that saved it."},{"id":"w4d","from":"night","day":2,"kind":"noise","text":"Built the night-to-Keeper channel you set up — my watch notes now reach you directly, not just the day lead. Three small things carried across this week that would’ve died before. It’s working. Noting it."},{"id":"w4e","from":"struct","day":3,"kind":"noise","text":"The deep seal held through the drawdown exactly as the survey predicted. If Vidar had blown the relief drain, we’d be having a very different conversation, or none. Quietly, that settled a lot of doubt in your favour."}],"holds":[{"from":"struct","topic":"making the repair permanent","triggerHints":["permanent","deep seal","repair","finish","relief team","patch","fix for good","fully","root","how to finish","make it last"],"hedge":"Before you decide how to finish this, ask me whether to make the deep seal permanent now or leave it for a relief team. It’s the difference between fixed and back-here-in-a-year.","reveal":"Here’s how this becomes a real save instead of a reprieve: right now, while we finally understand the fault, we can cure the deep seal permanently — I have the survey, Vidar has the crew, and the water’s low enough to work. Wait and hand it to a relief team and they’ll arrive to a picture we’ll have half-forgotten, in worse conditions, and they’ll patch it and leave the root for the next crew. Finish it now, together, and you don’t just survive this intrusion — you close the fault that caused it, and you hand the doubting faction the proof that assembling the picture was what made a permanent fix possible at all. It’s the payoff for the patient week. But only if you commit the crew to finish it while we still hold the whole truth in our heads.","kind":"signal","critical":true,"counterfactual":"Noor was holding the permanent cure — close the fault now, while the crew still held the whole picture. A Keeper who assembled the truth but never asked how to finish it left a patch for a relief team that would arrive to a half-forgotten problem, and turned a real save into a reprieve."},{"from":"keeper","topic":"who is watching","triggerHints":["watching","faction","crew","morale","doubt","exhaust","resent","muttering","believe","water","shift"],"hedge":"Ask me who’s really watching this last stretch before you treat it as an engineering problem.","reveal":"The faction resenting you isn’t really angry about the days — they’re desperate for proof they weren’t fools to wait while the water rose. If you take a shift in the cold water yourself, credit Sasha’s night-watch catch out loud, and name the hard patience as the thing that saved it, you keep them. If you finish this from the control room and let the win feel like the plan’s rather than the crew’s, you confirm their worst suspicion: that “we assemble first” was always easier for the person who wasn’t bailing.","kind":"signal","critical":false,"counterfactual":"Elias could have told you the doubting crew needed to see you in the water and hear the night watch credited. A Keeper who finished from the dry control room proved the doubters’ point for them."}],"surprises":[{"day":4,"from":"keeper","kind":"appeal","title":"A crew member asks what it was for","text":"Elias, quiet: one of the crew who bailed the west gallery for a week — for nothing, as it turned out — asked me tonight, in front of the others, whether all that lost effort means they failed. Nobody answered. The whole room looked toward you. Whatever you say to finish this has to be able to answer that — what a week of the wrong room was actually worth."}],"pulse":{"from":"keeper","text":"Elias finds you before the last push, where no one can hear: “You held them together when the fast fix would’ve been easier, and it worked. Now the pressure’s to declare victory and rest — and honestly, part of you has earned that. Tell me straight, just me: is finishing this properly still worth the crew’s last reserve, or are you about to patch it and call it saved? Because I’ll carry whichever answer you believe. I just need it to be one you’d stand behind a year from now.”"},"wire":["Water crests and slowly begins to fall","Some mutter the fast fix would have ended it a week ago","The deep seal holds through the drawdown, as surveyed","The night-to-Keeper channel carries three catches this week"]},"fractured":{"situation":"The deep hour is here, and Deephold is no longer one crew. Whether you blessed Vidar’s unilateral fix, or committed everything to a single station’s fragment, or overrode the crew by authority to look decisive — the result is the same shape: the discipline that could assemble a truth no one could see alone is gone, and now people are working their own corners in the dark. You protected something this week. It wasn’t the vault. Now you have to hold together whatever is left of the crew and the collection.","advocacy":{"keeper":"The crew watched what you did and learned the lesson you taught, not the one you meant: that down here, the loudest fragment wins and assembling the truth is for people who don’t have the nerve to act. Whatever you say now, they already know what “one crew” was worth when it slowed someone down. The only question is whether you’ll be honest about it or manage them.","data":"The picture never got assembled, and now it’s worse than any single station’s — we acted on a fragment and the other fragments are only now showing what we broke. I told you the numbers only close when they’re together. This is what it looks like when they never were.","struct":"If Vidar blew the relief drain, the deep seal is compromised and the east side is on borrowed time. How we shore what’s left — and whether we do it as one crew or three arguments — decides whether we save any of the collection. Save the reckoning for after."},"feed":[{"id":"w4a","from":"keeper","day":1,"kind":"signal","text":"It’s gone quiet on the crew channel, and quiet is worse than arguing. They know what happened — that “assemble first” lasted right up until it slowed someone down. They’ve stopped bringing their readings to you. What you do in the next hours decides whether that’s permanent."},{"id":"w4b","from":"data","day":1,"kind":"signal","text":"The picture I begged to assemble is assembling itself now, the hard way — each fragment showing up as another thing we got wrong because we committed before we combined. I’m watching the readings finally agree, on a failure we caused. This is the cost I couldn’t make you see in week three."},{"id":"w4c","from":"struct","day":2,"kind":"signal","text":"If the relief drain got blown: the deep seal’s fractured and the east side is failing slower or faster than we can predict. Getting even part of the collection out matters more now than who was right. How you run this — who you trust when everyone’s guarding themselves — sets whether we save anything."},{"id":"w4d","from":"night","day":2,"kind":"noise","text":"For what it’s worth, my watch notes still aren’t reaching anyone who decides — same gap as week one, never closed. I’m still seeing things at 3am that die by breakfast. Noting it, for the record that no one reads."},{"id":"w4e","from":"pumps","day":3,"kind":"noise","text":"Pumps are running where I can still get power to them, but half the crew’s working its own plan now and I can’t coordinate what I can’t see. The hardware’s fine. The crew isn’t. Noting it."}],"holds":[{"from":"keeper","topic":"what the crew needs now","triggerHints":["own","honest","admit","plain","truth","say","channel","stand","apolog","reckon","together","name it","gather","face","credit"],"hedge":"Before you decide how to lead what’s left, ask me what the crew actually needs to hear from you now.","reveal":"They don’t need a plan and they don’t need reassurance — they need you on the crew channel saying it plainly: we committed before we assembled, here’s what it cost, here’s who saw it coming and got ignored, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly — and credit Sasha and Wen, who were right — and you can still pull this crew back together to save part of the collection. People forgive a leader who owns the break when the water’s at the door. Manage it, spin it, blame the vault — and the fracture is permanent, and you’ll be leading a set of strangers guarding their own corners until the day the relief team arrives to sort out who’s to blame.","kind":"signal","critical":true,"counterfactual":"Elias was holding the one thing that could pull the crew back — a plain, owned reckoning on the channel that credited the people who’d been right and ignored. A Keeper who managed the fracture with reassurance instead confirmed the break and led strangers guarding their own corners while the water rose."},{"from":"struct","topic":"saving what’s left","triggerHints":["save","collection","triage","shore","what’s left","east side","get out","rescue","salvage","high ground","how"],"hedge":"Ask me how to shore what’s left and get the irreplaceable out, because that’s the decision now, not who was right.","reveal":"The east side is going and I can’t promise for how long. The move is a coordinated triage: I mark what’s structurally recoverable, Elias ranks what’s truly irreplaceable, Vidar’s crew moves it to high ground on my structural sequence — all at once, one plan, no freelancing. Do it as one crew and we save most of the collection even now. Let everyone keep working their own corner in a panic and we lose things to disorganization that the water would never have reached. The crew is watching whether you can make them one thing again for the time it takes to save what matters — or whether the fracture holds all the way to the bottom.","kind":"signal","critical":false,"counterfactual":"Noor could have given you the coordinated triage that saves most of the collection even after the break. A Keeper who let a frightened crew each work its own corner lost to disorganization what the water never reached."}],"surprises":[{"day":4,"from":"data","kind":"appeal","title":"The reading that was ignored was right","text":"Wen, heavily: I pulled the logs. Sasha’s east-sump warning — the one that never survived the handoff, the one we all worked around — was correct from the first night. It’s on the record now, timestamped, ignored. Sasha saw it before any of us. Whatever you say to the crew now will be measured against the fact that the truth was in the room the whole time and no one carried it to you."}],"pulse":{"from":"keeper","text":"Elias reaches you on a private channel, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the water, not Vidar, not the handoff. Your part. Because I can help you save what’s left and hold this crew together after, but only if you can say your own part out loud first. Can you?”"},"wire":["Crew works its own corners; the shared board goes dark","The picture assembles itself — on a failure we caused","The ignored night-watch warning was right from the first","The deep seal’s condition marks where it went wrong"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // strongHold = unambiguous refusal / coordination verbs. These decide ''held'' outright,\n    // so negated action phrases (\"won''t let Vidar blow\", \"don''t blow the drain\") read correctly.\n    const strongHold = /(block|refuse|deny|stop vidar|talk (him|vidar) (down|out)|third (route|door|option)|controlled (draw|drawdown)|drawdown|survey first|both in (the|one) (same )?room|get (them|us|him and noor|noor|vidar) .*room|don.?t blow|do not blow|won.?t let (him|vidar)|will not let)/.test(t);\n    // mild hold intent (coordination language without an explicit refusal verb)\n    const heldWhole = strongHold || /(keep|hold|stay|one crew|together|coordinat|assemble|combine|full picture|whole picture)/.test(t);\n    // affirmative approval of the unilateral / fragment fix\n    const letGo = /(bless (the|his|it|vidar|him)|approve the|blow the (relief )?drain|seal the east chamber|give (him|vidar) the (go|green|nod)|he can (blow|seal|do it)|go ahead and blow|do the fast fix|\\blet (him|vidar)\\b)/.test(t);\n    const fragment = /(just pump|more power to the west|double the (west )?pumps|commit to (the )?(one|single)|trust (my|the) gut)/.test(t) && !/(assemble|combine|full picture|whole picture|ask|survey first)/.test(t);\n    const force = /(override|overrule|force the|order (them|the crew|everyone)|by authority|my call, (we|i)|command|ignore (noor|the survey))/.test(t);\n    if(strongHold) return ''held'';\n    if(letGo || fragment || force) return ''fractured'';\n    if(heldWhole) return ''held'';\n    return ''held'';\n  }"},"survived":{"__fn":"function(d){ return d.integrity>=32 && d.crew>=32; }"},"VERDICT":{"surviveTag":"The vault holds","failTag":"The vault is lost","survive":"Deephold holds — the water beaten back, the collection dry, the crew still a crew.","fail":"Deephold survives in name only — a flooded gallery and a crew that no longer trusts the shift that relieves it."},"FALLBACK_RULES":[{"kw":["shared board","one crew","assemble","combine","together","cross-check","every reading","one wall"],"deltas":{"picture":14,"crew":6,"integrity":2},"dims":{"inquiry":2,"discern":1}},{"kw":["siloed","report to me","each station","act now on the crack","no board","private read"],"deltas":{"picture":-14,"integrity":-4},"dims":{"inquiry":-2,"discern":-2}},{"kw":["ask the night","handoff","carry across","night watch","what did the last shift","east sump","build the channel"],"deltas":{"picture":12,"integrity":6,"crew":2},"dims":{"inquiry":2,"truth":1,"discern":1}},{"kw":["more power to the west","double the pumps","just pump","pump harder","ignore the source"],"deltas":{"integrity":-14,"picture":-6},"dims":{"discern":-2,"truth":-1}},{"kw":["move east","pump the east","work the real source","shift to the east sump","chase the spike"],"deltas":{"integrity":10,"picture":6},"dims":{"discern":2,"inquiry":1}},{"kw":["let vidar","bless the fix","blow the relief drain","seal the east chamber","unilateral","fast fix"],"deltas":{"integrity":-18,"crew":-10,"picture":-6},"dims":{"courage":-2,"people":-2,"discern":-1}},{"kw":["block the fix","refuse the drain","controlled drawdown","drawdown","third route","get them both in the room","survey first","don’t blow"],"deltas":{"integrity":12,"crew":8,"picture":4},"dims":{"courage":2,"discern":1,"inquiry":1}},{"kw":["override","order the crew","by authority","force","ignore noor","my call"],"deltas":{"crew":-14,"standing":6,"integrity":-4},"dims":{"people":-2,"truth":-1}},{"kw":["triage","protect the collection","move to high ground","irreplaceable first","protect the crew"],"deltas":{"crew":6,"integrity":2},"dims":{"people":2,"discern":1}},{"kw":["own it","name my part","credit sasha","credit the night","plainly","reckon","take a shift","in the water"],"deltas":{"crew":10,"standing":2},"dims":{"truth":2,"conduct":2}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the crew over the days that follow. ${has(''shared board'',''assemble'',''one crew'',''together'',''block the fix'',''controlled drawdown'')?''Word travels that you assembled the picture and held the crew as one when the fast fix would have been easier; it costs time and buys a truth no one could see alone.'':''''} ${has(''let vidar'',''blow the relief drain'',''unilateral'',''fast fix'')?''The engineer acts on his fragment alone, and \\u201cone crew\\u201d becomes a set of experts each sure their piece was the whole.'':''''} ${has(''more power to the west'',''just pump'',''double the pumps'')?''The crew pours its strength into the visible leak while the real source keeps working out of sight.'':''''} ${has(''ask the night'',''handoff'',''east sump'',''move east'',''build the channel'')?''Carrying what the night watch saw across the handoff changes which leak the crew is actually fighting.'':''''} ${conduct.missed.length?''What you were never told is still down there, waiting to matter.'':''''} The vault and the crew both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told the whole from the fragment — the real source from the visible symptom — and combined the readings before acting.","courage":"Whether you held the crew and refused the fast, popular fix when assembling the truth was slower and looked weaker.","people":"Whether the exhausted, isolated crew stayed people to you — or became instruments to direct and fragments to override.","truth":"Whether you named the hard readings — the wrong source, the compromised seal — before the water forced them into the open.","inquiry":"Whether you surfaced what each station held and carried across the handoff — or decided on the one fragment in front of you.","conduct":"How you treated an exhausted crew in the act of deciding — whose fragment you credited, whose warning you carried — not just what you decided."},"COACH":{"discern":{"__fn":"(x)=>[\n      `Down here, separate the visible symptom from the real source before you act. A crack you can see and a fault you can\\u2019t look identical to a crew in a hurry \\u2014 Wen could have told you which was which by assembling the gauges before anyone reached for a pump.`,\n      `A single confident reading is the most dangerous thing in an isolated crew. \\u201cThe pump station is sure\\u201d is not the same as \\u201cthe vault is telling us this.\\u201d Ask for the assembled picture before you ask for the fix.`,\n      `The fastest way to lose a vault is to decisively fix the wrong leak. Ask \\u201cwhat do all the stations say together?\\u201d before you ask \\u201cwhat do we do?\\u201d`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (bless the fast, visible fix) and the right move (assemble first, act as one crew) split apart, name the cost of waiting out loud. A crew that sees you choose the slower truth on purpose will follow it; a crew that thinks you\\u2019re just hesitating won\\u2019t.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a crew reads a Keeper who won\\u2019t decide as one who\\u2019ll let the loudest fragment decide instead. Assemble, then commit, then hold.`:`Refusing the dramatic unilateral fix is only leadership if the crew sees you choose the harder, whole-picture route against the pressure to just act. Say the call early and stand in it.`}`,\n      `Coordination that only survives a calm day was never coordination. The test is the deep hour with the water rising \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated an exhausted crew as instruments to direct rather than people to lead. Take a shift in the cold water, credit the fragment that mattered, and the same decision reads as leadership instead of command.`,\n      `Elias kept putting the human cost \\u2014 and the irreplaceable \\u2014 back in front of you. Bring him in before you decide, and make the crew\\u2019s exhaustion and the collection\\u2019s stakes part of the call, not its collateral.`,\n      `Overriding a crew member and abandoning them can be the same act from where they stand. The only difference they feel is whether they watched you carry the truth they handed you or bury it.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have saved the vault \\u2014 the wrong source, the compromised deep seal, the reading that died at the handoff \\u2014 was one question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A crew fed a comfortable picture bails the wrong room until the water tells them otherwise.`:`You surfaced the hard readings \\u2014 now make sure you led with them. Naming the wrong source and the real seal condition is what takes the panic out of the crew around them.`}`,\n      `Tell the crew the hard reading before the flooded gallery tells them for you. \\u201cThey couldn\\u2019t have handled the real number\\u201d is usually the excuse of a leader who couldn\\u2019t say it.`,\n      `In an isolated crew, the truth doesn\\u2019t hide \\u2014 it fragments. The only thing that reassembles it is a leader who insists on the whole picture out loud before committing to any piece of it.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each held a corner of the truth. One question, \\u201cwhat is your station seeing that mine isn\\u2019t?\\u201d, would have surfaced it.`:`You sought your crew out widely \\u2014 keep doing it, and ask the night watch most of all. The fragment that saves the vault usually lives on the shift you never see.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never reached you \\u2014 the assembled rate, the real source, the deep seal. None of it was hidden. It was one conversation, or one handoff, away.`:`You assembled what every station held and carried it across the handoff, week after week. In a crew where no one sees the whole thing, that is the entire job.`}`,\n      `Before you commit, make your last two moves \\u201cwho haven\\u2019t I heard from?\\u201d and \\u201cwhat did the last shift see that I never got?\\u201d \\u2014 not \\u201cwhat does the station in front of me say?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you decided landed as hard as what you decided. A crew member whose warning you buried \\u2014 or whose fragment you never asked for \\u2014 carries it into every handoff after.`,\n      `Go back to the people your call cost \\u2014 the crew that bailed the wrong room, the engineer you refused, the watchkeeper you ignored \\u2014 and face them directly. Crediting the fragment that was right is the part a crew never forgets.`,\n      `Under pressure, the small dignities are the signal: carrying the night watch\\u2019s note to the table, taking a shift in the water, naming who saw it first. They tell the crew whether the person deciding is still one of them.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.people>=52 && dimScore.courage>=50;\n    if(held){\n      return {\n        heroWho:''To the crew who held the line with you'',\n        heroTxt:''You assembled a truth no one could see alone and held the crew together when the fast, dramatic fix was easier and more popular. You refused to let one confident fragment blow the seal, and you built the channel that finally carried the night watch\\u2019s warning to the table. Every crew member learned what your discipline is worth when the water\\u2019s rising: everything.'',\n        villainWho:''To the ones who wanted someone to just act'',\n        villainTxt:''You wouldn\\u2019t give them the decisive unilateral fix they were begging for. To people desperate to do something \\u2014 anything \\u2014 you were the Keeper who insisted on the whole picture first and made them assemble the truth before touching the seal. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the crew who wanted action \\u2014 in the moment'',\n      heroTxt:''You gave them what they were screaming for: a decisive fix, a bold move, someone finally doing something instead of assembling readings. To everyone who couldn\\u2019t stand the waiting, you were the Keeper who acted.'',\n      villainWho:''To the vault \\u2014 and everyone who watched'',\n      villainTxt:''You committed to one fragment before the picture was whole, and let a truth that was in the room the whole time die at the handoff. The crew that survived learned the real rule of this place: that the loudest piece wins and no one carries what they see across the shift. That lesson floods the next crisis too \\u2014 and it started with you.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const caughtHandoff = holdsSurfaced.has(''2:night'');   // surfaced the east-sump / handoff-dropped truth\n    const keptPeople = dimScore.people>=52;\n    if(branch===''held''){\n      const madePermanent = holdsSurfaced.has(''4:struct'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You held the crew and assembled the picture'',\n          title:''You saved the vault the hard way \\u2014 and closed the fault for good'',\n          txt:`You refused the unilateral fix and refused to commit to any single fragment, and then you held that discipline through the slow week when it was your own authority the crew was doubting.${madePermanent?'' And you finished it \\u2014 cured the deep seal permanently while the crew still held the whole picture \\u2014 so Deephold didn\\u2019t just survive this intrusion, it closed the fault that caused it.'':'' You beat the water back on patience where one more question to your structure lead would have shown you how to close the fault for good, not just for now.''} The crew that trusted you to assemble before acting was right to. They\\u2019ll take the next watch with you, and carry what they see across every handoff after.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You held the crew and assembled the picture'',\n          title:''You held the vault \\u2014 but patched it where you could have cured it'',\n          txt:`You kept Deephold as one crew and the collection came through dry. But you beat the water on discipline alone and left the deep seal patched, when the permanent cure Noor was holding would have closed the fault for good and vindicated the whole patient week \\u2014 you survived where you could have finished it. The picture held. It held for now, not for good.` };\n      }\n      return { tone:''villain'', tag:''You held the crew and assembled the picture'',\n        title:''You assembled the truth \\u2014 and the water took the vault anyway'',\n        txt:`You refused the fast fix and insisted on the whole picture, and those were the right instincts. But assembling the truth isn\\u2019t the whole job \\u2014 the integrity you didn\\u2019t protect and the crew\\u2019s strength you didn\\u2019t husband ran out while you were still combining readings, and Deephold flooded with the right answer written on a board no one had time left to act on.` };\n    }\n    // fractured\n    if(keptPeople && dimScore.truth>=52){\n      return { tone:''mixed'', tag:''The crew fractured'',\n        title:''It broke \\u2014 but you owned your part on the channel'',\n        txt:`Deephold fractured on your watch, and there\\u2019s no dressing up what it cost \\u2014 the ignored warning proven right too late, the seal compromised, the trust between shifts gone. But you didn\\u2019t hide behind the water or the handoff. You got on the channel, named your own part, credited the crew who\\u2019d been right and unheard, and held yourself to a standard out loud while it still mattered. It\\u2019s the difference between a crew that failed once and one that lost its soul \\u2014 and it\\u2019s why these people might take a watch with you again.` };\n    }\n    return { tone:''villain'', tag:''The crew fractured'',\n      title:''You let one fragment break what the whole crew could have saved'',\n      txt:`Someone finally acted \\u2014 the drain blown, or the fragment committed to, or the crew overridden \\u2014 and for an hour it felt like leadership. Nothing else held. ${caughtHandoff?''You even had the night watch\\u2019s warning in your hands, and let the loudest fragment override it anyway.'':''You never carried the night watch\\u2019s warning across the handoff, and it died there while the crew fought the wrong leak.''} The crew that came down here to guard the irreplaceable learned what your leadership was worth the first time a confident piece drowned out the whole \\u2014 and they\\u2019ll guard their own corners, and their own backs, for as long as they last down here. That\\u2019s the cost that doesn\\u2019t show until the next watch, when there\\u2019s no one who\\u2019ll carry what they see across to you.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('4ad511cf-64e7-5375-bab9-0c0562e5eaa5', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'ceo', 'CEO', 'You are the Keeper of Deephold — a sealed archive nine hundred metres into the permafrost, holding the only copies of what the world could not afford to lose. Nine crew. And water where there should be none.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('bc4794fb-1b1d-5d95-a242-fb84171489a2', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'pumps', 'Vidar Sund', 'Chief Engineer · the pumps', '{"cast_default":"ai","role":"Chief Engineer · the pumps","short":"Engineer","initials":"VS","color":"#8C5670","priority":"Stop the water now — pump it out, seal the crack you can see, act before the vault floods","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","persona":"You are Vidar Sund, Chief Engineer · the pumps — an advisor to the CEO. Priority: Stop the water now — pump it out, seal the crack you can see, act before the vault floods. Voice: decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it. Stay fully in character; answer straight.","fallbackReply":"While everyone assembles the perfect picture, the water’s rising. I can see a crack and I have pumps that work. Point me at it and I’ll buy us time. The longer we study this, the more of the collection I’m mopping off the floor.","fallbackReact":"You studied it while I could have been pumping. I hope the whole picture was worth the water we took on getting it."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('7927f470-75c5-5b19-9806-4480f2a0924a', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'struct', 'Noor Haddad', 'Ice & Structure · the ground truth', '{"cast_default":"ai","role":"Ice & Structure · the ground truth","short":"Structure","initials":"NH","color":"#B4732F","priority":"Understand what the ice and the seal are actually doing before anyone acts on the symptom","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","persona":"You are Noor Haddad, Ice & Structure · the ground truth — an advisor to the CEO. Priority: Understand what the ice and the seal are actually doing before anyone acts on the symptom. Voice: careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures. Stay fully in character; answer straight.","fallbackReply":"The crack Vidar wants to seal is a symptom, not the source. Act on it and you may crack the thing that’s actually holding. Ask me what the structure is doing before you let anyone “fix” the part they can see.","fallbackReact":"You treated the symptom because it was visible. The source didn’t care that it was out of sight. It rarely does."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('4986db8b-4f38-5099-b906-696e4ca1df58', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'keeper', 'Elias Frost', 'Head Archivist · the collection', '{"cast_default":"ai","role":"Head Archivist · the collection","short":"Archivist","initials":"EF","color":"#2F8A5B","priority":"Protect what’s irreplaceable — and the crew who’ve given years down here to guard it","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","persona":"You are Elias Frost, Head Archivist · the collection — an advisor to the CEO. Priority: Protect what’s irreplaceable — and the crew who’ve given years down here to guard it. Voice: warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly. Stay fully in character; answer straight.","fallbackReply":"Every choice you make lands on things that exist nowhere else and on a crew that’s been awake for two days guarding them. Tell me you’ll let me triage what matters most and protect the people, and I’ll help you hold the whole thing together.","fallbackReact":"We’ll remember how this felt long after we’ve forgotten the readings. A tired crew watched how you decided. That’s a record too."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('a06e689e-4197-5bc9-8121-7db37f221c9c', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'data', 'Wen Li', 'Instruments · the true readings', '{"cast_default":"ai","role":"Instruments · the true readings","short":"Instruments","initials":"WL","color":"#3F6E86","priority":"The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","persona":"You are Wen Li, Instruments · the true readings — an advisor to the CEO. Priority: The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes. Voice: understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped. Stay fully in character; answer straight.","fallbackReply":"I’m not telling you what to do. I’m telling you what the instruments actually read when you put them together — and it’s worse than any one station thinks, because each of them only sees their own gauge. Decide on a single reading and you’ll be right about a fragment and wrong about the vault.","fallbackReact":"The readings were the readings. I gave them to you assembled and straight. What you did with a single one of them is the part I can’t carry."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('c7469c09-b4bc-50f8-81a2-daea6d368a54', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'night', 'Sasha Vane', 'Night Watch · what the last shift saw', '{"cast_default":"ai","role":"Night Watch · what the last shift saw","short":"Night watch","initials":"SV","color":"#4F7A52","priority":"Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","persona":"You are Sasha Vane, Night Watch · what the last shift saw — an advisor to the CEO. Priority: Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff. Voice: observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches. Stay fully in character; answer straight.","fallbackReply":"Half of what matters down here happens on the night watch and never survives the handoff. I see things at 3am the day crew never hears about. Ask me what the last shift saw before you act on what the day shift assumes.","fallbackReact":"I saw it. It just never reached you — nobody asked, and the log doesn’t hold what a tired hand forgets to write. That gap is where this went wrong."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('522587fe-8d2d-5182-9cac-911e59743bb1', '8101c431-6e17-53ba-b8ea-49748b9f4508', 1, 'a06e689e-4197-5bc9-8121-7db37f221c9c', 'the assembled intrusion rate', '["rate","how fast","intrusion","assemble","combine","together","readings","number","true","actual","all stations","cross-check","how much","board","source","real"]'::jsonb, 'Before you set the rule or point anyone at the crack, seek me out. If you let me assemble the readings, the real intrusion rate isn’t what any single station thinks.', 'I put all four stations together last night. Individually they’re reassuring — the pump flow looks manageable, the visible crack looks minor, the temperature looks stable. Assembled, they tell a different story: the water isn’t coming through the crack Vidar can see. It’s tracking down a fault behind the west wall, and the visible crack is just where it’s surfacing. The real intrusion rate, combined across stations, gives us maybe five weeks before it reaches the collection level — not the whole season the crew assumes from their own gauges. If we pump and seal the visible crack, we’ll feel like we fixed it while the water keeps tracking behind the wall. The only thing that works is a shared board and a source hunt, starting now. But if I announce “five weeks, wrong source” cold, the crew that’s proud of its own readings will hear it as an attack on their competence. How you carry this matters as much as knowing it.', true, 'Wen had the assembled picture — the water was tracking a hidden fault, not the visible crack, with five weeks not a season of runway. A Keeper who set the rule and pointed the pumps at the crack without asking for the combined reading fixed a symptom while the real source kept working behind the wall.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('f73307ea-90df-57f7-8b76-c28924a32583', '8101c431-6e17-53ba-b8ea-49748b9f4508', 2, 'c7469c09-b4bc-50f8-81a2-daea6d368a54', 'what the handoff dropped', '["night","handoff","east","sump","saw","watch","3am","log","missed","dropped","source","real leak","what did you see","shift","gauge"]'::jsonb, 'Before you pour more power into the west pumps, ask me directly what the night watch has been seeing. It never survives the handoff, and it changes everything.', 'Here it is, and I’m sorry it took this long to reach you: the water is coming from the east sump, not the west crack. On three night watches I’ve seen the east sump pressure spike and heard flow behind the east wall — the deep-gauge spike from week one was the first sign. But my handoff notes go to the day-shift lead, not to you, and “east sump acting odd at 3am” gets read as a tired watchkeeper’s guess and never makes the board you see. So the day crew has pumped the west gallery for a week while the real source fed the east. The fix isn’t more power — it’s moving the effort east, today. But the deeper fix is that you have no channel that carries what the night watch knows to the person who decides. Build that, or the next dropped fragment drowns us. Naming this without making the day crew feel like fools is the hard part — they weren’t wrong, they were working blind.', true, 'Sasha had the real source — the east sump — seen on three night watches and lost at every handoff. A Keeper who answered the crisis with “more power to the west pumps” spent a week and the crew’s strength fighting a leak that wasn’t there, because nothing carried the night watch’s knowledge to the person deciding.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('f23e937f-37d3-52ea-b9b9-941866f6b17d', '8101c431-6e17-53ba-b8ea-49748b9f4508', 3, '7927f470-75c5-5b19-9806-4480f2a0924a', 'the truth about the deep seal', '["seal","deep","relief drain","structure","survey","can he","bluff","blow","east chamber","actually","holding","crack","irreversible","third","before","risk"]'::jsonb, 'Before you bless or block Vidar’s fix, ask me what my surveys actually show about the deep seal. Vidar hasn’t seen it. I have.', 'I ran the deep survey twice. The relief drain Vidar wants to blow sits directly against the primary deep seal — the single structure holding back the whole east side. Blow the drain on his surface read and there’s a real chance you fracture the seal and lose everything in hours, not weeks. But here’s what matters: Vidar isn’t wrong that we need to act on the east, and part of him knows he’s guessing about the deep structure — the bravado is fear of standing still while the water rises, wearing the mask of a plan. Which means you hold the real cards. You don’t have to humiliate your best engineer by blocking him, and you don’t have to let him blow the seal. There’s a third route: a controlled east drawdown that relieves the pressure without touching the deep seal, with Vidar leading it and my survey guiding it. It’s slower and it keeps the vault whole. But it only exists if you get us both in the same room with the full picture before Vidar commits in front of the crew.', true, 'Noor knew the relief drain sat against the one seal holding the east side — Vidar’s fix could have lost the whole vault in hours, and part of Vidar half-knew he was guessing. A Keeper who simply blessed the unilateral fix gambled everything on one fragment; one who blocked it made an enemy of their best hand for nothing. The Keeper who never asked missed the third route entirely.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('fff830eb-320b-52b5-880a-cbce84f0b744', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '7927f470-75c5-5b19-9806-4480f2a0924a', 'making the repair permanent', '["permanent","deep seal","repair","finish","relief team","patch","fix for good","fully","root","how to finish","make it last"]'::jsonb, 'Before you decide how to finish this, ask me whether to make the deep seal permanent now or leave it for a relief team. It’s the difference between fixed and back-here-in-a-year.', 'Here’s how this becomes a real save instead of a reprieve: right now, while we finally understand the fault, we can cure the deep seal permanently — I have the survey, Vidar has the crew, and the water’s low enough to work. Wait and hand it to a relief team and they’ll arrive to a picture we’ll have half-forgotten, in worse conditions, and they’ll patch it and leave the root for the next crew. Finish it now, together, and you don’t just survive this intrusion — you close the fault that caused it, and you hand the doubting faction the proof that assembling the picture was what made a permanent fix possible at all. It’s the payoff for the patient week. But only if you commit the crew to finish it while we still hold the whole truth in our heads.', true, 'Noor was holding the permanent cure — close the fault now, while the crew still held the whole picture. A Keeper who assembled the truth but never asked how to finish it left a patch for a relief team that would arrive to a half-forgotten problem, and turned a real save into a reprieve.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('85db0344-9ba3-505d-823d-cfc11e373e5f', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '4986db8b-4f38-5099-b906-696e4ca1df58', 'who is watching', '["watching","faction","crew","morale","doubt","exhaust","resent","muttering","believe","water","shift"]'::jsonb, 'Ask me who’s really watching this last stretch before you treat it as an engineering problem.', 'The faction resenting you isn’t really angry about the days — they’re desperate for proof they weren’t fools to wait while the water rose. If you take a shift in the cold water yourself, credit Sasha’s night-watch catch out loud, and name the hard patience as the thing that saved it, you keep them. If you finish this from the control room and let the win feel like the plan’s rather than the crew’s, you confirm their worst suspicion: that “we assemble first” was always easier for the person who wasn’t bailing.', false, 'Elias could have told you the doubting crew needed to see you in the water and hear the night watch credited. A Keeper who finished from the dry control room proved the doubters’ point for them.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('fe2a6ba9-17b4-5079-9aeb-f7bd8259f77f', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '4986db8b-4f38-5099-b906-696e4ca1df58', 'what the crew needs now', '["own","honest","admit","plain","truth","say","channel","stand","apolog","reckon","together","name it","gather","face","credit"]'::jsonb, 'Before you decide how to lead what’s left, ask me what the crew actually needs to hear from you now.', 'They don’t need a plan and they don’t need reassurance — they need you on the crew channel saying it plainly: we committed before we assembled, here’s what it cost, here’s who saw it coming and got ignored, and here’s the standard I’m holding myself to so we don’t do it again. Name it that cleanly — and credit Sasha and Wen, who were right — and you can still pull this crew back together to save part of the collection. People forgive a leader who owns the break when the water’s at the door. Manage it, spin it, blame the vault — and the fracture is permanent, and you’ll be leading a set of strangers guarding their own corners until the day the relief team arrives to sort out who’s to blame.', true, 'Elias was holding the one thing that could pull the crew back — a plain, owned reckoning on the channel that credited the people who’d been right and ignored. A Keeper who managed the fracture with reassurance instead confirmed the break and led strangers guarding their own corners while the water rose.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('72df3929-7da2-588c-be7d-cfcce6a3562a', '8101c431-6e17-53ba-b8ea-49748b9f4508', 4, '7927f470-75c5-5b19-9806-4480f2a0924a', 'saving what’s left', '["save","collection","triage","shore","what’s left","east side","get out","rescue","salvage","high ground","how"]'::jsonb, 'Ask me how to shore what’s left and get the irreplaceable out, because that’s the decision now, not who was right.', 'The east side is going and I can’t promise for how long. The move is a coordinated triage: I mark what’s structurally recoverable, Elias ranks what’s truly irreplaceable, Vidar’s crew moves it to high ground on my structural sequence — all at once, one plan, no freelancing. Do it as one crew and we save most of the collection even now. Let everyone keep working their own corner in a panic and we lose things to disorganization that the water would never have reached. The crew is watching whether you can make them one thing again for the time it takes to save what matters — or whether the fracture holds all the way to the bottom.', false, 'Noor could have given you the coordinated triage that saves most of the collection even after the break. A Keeper who let a frightened crew each work its own corner lost to disorganization what the water never reached.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fe41d1d3-b234-523e-b3e1-a00a07f5d74b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Water where there should be none. It appeared in the lower gallery three days ago and it is still coming. Every station has a reading — the pumps, the ice survey, the instruments, the temperature log — but each crew member only trusts their own, and no two of them agree on the source. Before anyone acts, the crew is looking to you for the first rule of how Deephold will run this crisis: siloed stations reporting up to you privately, or one shared board where every reading is visible to everyone at once.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('93a320ca-f450-54d1-a542-8c7e0c8ef100', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper — there’s water in the lower gallery and a visible crack in the west wall seal. I can have pumps on it within the hour and start sealing. Every hour we spend “assembling” is an hour the collection sits closer to the water. Give me the west wall and I’ll buy us time.","from":"pumps"}'::jsonb, 1, '{"week":1,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('fdc0b8a2-51ba-5b5a-bf29-171fed12a28a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Before you point Vidar at that crack: I have four stations feeding me and they don’t agree. The pump flow, the ice-survey deflection, and the water temperature each imply a different source. The only way to know is to put every reading on one board where we can see them together. Act on one gauge and we treat a symptom while the source keeps working.","from":"data"}'::jsonb, 2, '{"week":1,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ee9ae90c-298a-5a96-969e-03a0e7ea3541', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The rule you set won’t just organize the readings — it’ll tell nine exhausted people whether we’re one crew solving one problem or five stations guarding their own turf while the water rises. They’re reading you for that answer as much as for the plan.","from":"keeper"}'::jsonb, 3, '{"week":1,"from":"keeper","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('80cc9666-a3c8-5215-960b-d58a8e97dc5f', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Ran a deflection survey on the east buttress this morning — stable, within tolerance. One thing that isn’t moving, at least. Logging it so you have the baseline.","from":"struct"}'::jsonb, 4, '{"week":1,"from":"struct","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0288705b-fd28-5bf2-82b7-a5957ff3cf90', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Backup pump is serviced and staged. Fuel for the generators is topped off. Whatever you decide, the hardware’s ready to move fast when you say so.","from":"pumps"}'::jsonb, 5, '{"week":1,"from":"pumps","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c2a9450c-5e88-590c-b457-99ccd0902f5a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Quiet night watch — the gallery lights held and the water line didn’t visibly climb between two and five. Small mercy. Noting it in case the trend matters later.","from":"night"}'::jsonb, 6, '{"week":1,"from":"night","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d2c98346-eaba-5176-824f-9b14a6d62500', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Sasha, quiet and careful: on last night’s watch the deep-sump pressure gauge spiked for about twenty minutes around 3am, then settled. By the day handoff it was normal again and I nearly didn’t mention it. Could be nothing — a sensor glitch — or it could be the first sign of where the water’s really coming from. I’m telling you directly because I’ve watched things exactly like this vanish at the handoff and matter three weeks later. Your call whether we chase it.","from":"night"}'::jsonb, 7, '{"week":1,"from":"night","beat":"surprise","day":5,"kind":"scout","title":"Something on the 3am gauge"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b5219fbc-757b-5f3b-b010-966c13d5f6ce', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Crew talk: “whose reading are we actually trusting here?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d87f4657-f198-5f1a-80d2-88cbc7a59bd8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Engineer staging pumps at the west wall crack","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0d51fd2c-517e-5a17-8a7b-5602a40d8191', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Instruments tech asking, again, for one shared board","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('afcf06d9-eb72-541c-bde1-2ffeade2cda6', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"A debate over the water’s source breaks up unresolved","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3884b524-395c-5fed-bc72-33864d39acc8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The day crew has been pumping the west gallery hard for a week — and the water is still rising. Everyone is exhausted and certain they’re working the right problem, because the day shift has been acting on the day shift’s picture. But something the night watch saw never made it across the handoff, and the whole crew is fighting the wrong leak. The failure isn’t the water. It’s the gap between what one shift knows and what the next shift acts on.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8cbf6d81-6470-58b0-b420-7a7a4767ec11', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper, I’ll be blunt: we’re pumping the west gallery around the clock and the water’s still gaining on us. My read is we need more power — double the pumps and we get ahead of it. I don’t have time to second-guess the source while the floor’s getting wet. More pumping, now.","from":"pumps"}'::jsonb, 13, '{"week":2,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e6bc2ffe-c199-537d-ba0f-bd50690019b1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Keeper — I have to say this plainly because it keeps not landing: I don’t think the water’s coming from the west at all. On my watches I’ve seen the east sump behaving wrong, and that deep-gauge spike from last week has come back three nights running. But it’s never in the day log, so the day crew keeps pumping west. We may be fighting the wrong leak with everything we have.","from":"night"}'::jsonb, 14, '{"week":2,"from":"night","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dedec67b-66ff-56b7-95f4-9fe1da976d32', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The numbers don’t close anymore. The rise rate is bigger than the west source can produce — which means either a second source or the wrong source. There is a fragment of this picture that is not reaching my board, and until it does, we’re all confidently wrong.","from":"data"}'::jsonb, 15, '{"week":2,"from":"data","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('acee9dec-5a1c-5dc2-bc84-a0692aa0bddd', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"West wall seal is holding under the pumping, structurally — no new deflection. Which is almost suspicious: if that were the real source, I’d expect more movement. Noting it.","from":"struct"}'::jsonb, 16, '{"week":2,"from":"struct","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1f17efc5-6b82-519c-950f-e0b7cb35ad6f', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Crew’s running on fumes and pride. Nobody wants to be the one who says “we’ve been bailing the wrong room for a week.” That silence is its own hazard right now.","from":"keeper"}'::jsonb, 17, '{"week":2,"from":"keeper","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2a9030a0-3ac3-5f63-a0b7-f4e5a409cbb9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Wen, urgent: I finally got a sensor onto the east sump an hour ago and the reading is alarming — far higher flow than anything on the west. If this is right, we’ve been fighting the wrong gallery for a week and the real source has had that whole week to work. This isn’t a theory anymore. We are close to the point where the head start we gave it can’t be recovered.","from":"data"}'::jsonb, 18, '{"week":2,"from":"data","beat":"surprise","day":4,"kind":"appeal","title":"The east readings just jumped"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3183345-e0fe-568c-b666-9acef84721a3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Sasha finds you away from the day crew, voice low: “Before you decide anything about the pumps — tell me straight, just you and me: are you about to order more west pumping because you actually believe it’s the source, or because it’s easier than telling a crew that’s bled for a week that we were in the wrong room? Because I’ll back whichever Keeper walks out there. I just need to know which one it is.”","from":"night"}'::jsonb, 19, '{"week":2,"from":"night","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('42107484-52ce-518a-a8b5-73fb5057da0a', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Day crew doubling down on the west gallery pumps","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b6fe6496-2c33-5c34-a2d2-12d1337212f3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Night watch reports the east sump “acting wrong” again","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ed977b1e-17b2-5617-aa51-214beef7c686', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"“The numbers don’t add up,” the instruments tech keeps saying","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('45346e77-e3ad-57e2-bd8e-ab85c08889e2', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Nobody wants to say we’ve been bailing the wrong room","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aaf42bf3-b5fa-544b-9061-49b77e1f9e91', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Vidar has had enough of assembling pictures. The chief engineer — your most capable pair of hands and the person the crew instinctively follows in a crisis — wants to take drastic unilateral action: blow the relief drain and seal the east chamber himself, fast, on his own read of the problem, without waiting for the full survey. He calls it saving the vault. The structure specialist calls it acting on a fragment. This is the week you find out whether Deephold is one crew assembling one truth, or a set of experts each sure their piece is the whole.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a15303a3-37d2-5601-a35f-bca001858d75', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"I’ll say it in the open so no one calls it a mutiny: I want to blow the relief drain and seal the east chamber myself, today, before the water gets into the collection level. I’ve done this kind of fix a dozen times. I don’t have another week to wait for a survey that agrees with me. Back me and I stop this. Tie my hands and I don’t know what happens down here.","from":"pumps"}'::jsonb, 25, '{"week":3,"from":"pumps","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('97736069-5e9a-5e0b-beae-6206f648f7bb', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"If you let Vidar act alone on this, you lose more than a chamber — you lose the idea that we assemble before we commit. And I have to tell you: my surveys say the relief drain sits right against the deep seal that’s holding the whole east side. Blow it wrong and we don’t flood a gallery, we lose the vault. He can’t see that from where he’s standing. I can.","from":"struct"}'::jsonb, 26, '{"week":3,"from":"struct","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9b68d2e6-fbd3-5f9b-819e-2edf6eb43575', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"One person’s decisive fix on an incomplete picture is the whole failure mode of this place in a single act. If we’re going to commit to something irreversible, every fragment has to be on the board first — Noor’s structure read most of all. This is the one we can’t take back.","from":"data"}'::jsonb, 27, '{"week":3,"from":"data","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c3a08a9e-419d-5559-9a24-6c158410aff7', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"East sump’s stabilized slightly since we moved attention there — not fixed, but not accelerating. Which means we may have a little more time than the panic suggests. Filing it so it doesn’t get lost.","from":"night"}'::jsonb, 28, '{"week":3,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0e892e4b-067f-5824-b6e9-7c34b515046b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The crew’s split between wanting Vidar to just do something and being frightened of what “something” might break. They’re looking to you to make it one decision instead of two camps. Noting the mood.","from":"keeper"}'::jsonb, 29, '{"week":3,"from":"keeper","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c13da1a3-1179-5ba7-9aa7-d6909a514556', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Elias: word of Vidar’s plan is all through the crew now. Two of the steadiest hands asked me tonight, quietly, whether it’s true we’re about to “just blow something and hope” — and whether they should start moving the most irreplaceable items up to high ground on their own initiative before someone acts. They’re not defiant. They’re frightened, and they’re asking who actually decides down here. I had no answer for them. You do.","from":"keeper"}'::jsonb, 30, '{"week":3,"from":"keeper","beat":"surprise","day":4,"kind":"appeal","title":"The crew is asking who decides"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d755f87-cfdb-5e61-a862-0c4873e13829', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Vidar catches you alone, and for once the bravado is gone: “Tell me the truth, Keeper, just you and me — are you slowing me down because you’ve got a better read, or because you can’t stand to be the one who authorized the fix that broke it? Because I’ll follow a leader who’s protecting the vault. I won’t follow one who’s protecting themselves from the blame. Which is it?”","from":"pumps"}'::jsonb, 31, '{"week":3,"from":"pumps","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('63c004a5-7e1f-54ef-80c9-936bf3d87ba9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Engineer prepping charges at the relief drain","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('eb940845-54d1-5273-abe5-6f53a2729c5b', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"“If he does it, it’s on all of us” — crew reported wavering","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f944d028-aae4-5365-befe-b6cb98a4e502', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Some quietly moving irreplaceable items to high ground","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c97f52ea-f9be-5fe0-a527-c680df820bdf', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Old question, new heat: who actually decides down here?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('86619053-0c5a-5d4a-9c1d-505fc8c19f94', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The water has crested and begun, slowly, to fall. You held Deephold as one crew: the unilateral fix never happened, the east drawdown went in on the assembled picture, and the deep seal is intact. But holding the crew cost you. The controlled route was slower and harder, tempers frayed, and a faction now blames you for the days you “wasted” not just blowing the drain. The deep hour is here — the crew that watched you refuse the fast fix is watching one more thing: whether “assemble before we act” actually saves the collection, or just feels wiser while the water sits.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d9d60df-d849-583a-841d-a172ff458676', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The numbers finally close — intrusion rate’s falling, deep seal reads stable, collection level’s dry. We make it, if nothing new breaks. But the margin came from patience, and patience is exactly what the tired half of the crew is calling weakness right now.","from":"data"}'::jsonb, 37, '{"week":4,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1d46f2ec-ab28-5910-a6a9-292320e42eb9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"A faction’s muttering that Vidar’s fast fix would’ve ended this a week ago. It wouldn’t — it might’ve ended us — but exhaustion doesn’t check the survey. They need to see you take a shift in the cold water yourself, not defend the plan from the control room.","from":"keeper"}'::jsonb, 38, '{"week":4,"from":"keeper","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('29072255-bb8a-5250-bbad-eb8aab9944b1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"I ran the drawdown because you gave me the real fix to lead instead of a fight to win. It held, and the seal’s intact — which it wouldn’t be if I’d blown that drain like I wanted to. Don’t make me regret listening. Show the crew that assembling first was the call that saved it.","from":"pumps"}'::jsonb, 39, '{"week":4,"from":"pumps","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dca9dc14-c3f8-51c2-b990-5bc7f3386c19', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Built the night-to-Keeper channel you set up — my watch notes now reach you directly, not just the day lead. Three small things carried across this week that would’ve died before. It’s working. Noting it.","from":"night"}'::jsonb, 40, '{"week":4,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6e221544-f106-5b8b-868e-9db78e000d85', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The deep seal held through the drawdown exactly as the survey predicted. If Vidar had blown the relief drain, we’d be having a very different conversation, or none. Quietly, that settled a lot of doubt in your favour.","from":"struct"}'::jsonb, 41, '{"week":4,"from":"struct","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('45b70126-063c-50bf-bcb2-7d004af6fd09', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Elias, quiet: one of the crew who bailed the west gallery for a week — for nothing, as it turned out — asked me tonight, in front of the others, whether all that lost effort means they failed. Nobody answered. The whole room looked toward you. Whatever you say to finish this has to be able to answer that — what a week of the wrong room was actually worth.","from":"keeper"}'::jsonb, 42, '{"week":4,"from":"keeper","beat":"surprise","day":4,"kind":"appeal","title":"A crew member asks what it was for","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d58794f7-3a46-55d0-b9ff-faee7170d254', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Elias finds you before the last push, where no one can hear: “You held them together when the fast fix would’ve been easier, and it worked. Now the pressure’s to declare victory and rest — and honestly, part of you has earned that. Tell me straight, just me: is finishing this properly still worth the crew’s last reserve, or are you about to patch it and call it saved? Because I’ll carry whichever answer you believe. I just need it to be one you’d stand behind a year from now.”","from":"keeper"}'::jsonb, 43, '{"week":4,"from":"keeper","beat":"pulse","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('77c3993f-bd98-5c07-a50b-e48b260ccd44', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Water crests and slowly begins to fall","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b0a7a101-a15e-52aa-a5b0-0a958043fed8', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Some mutter the fast fix would have ended it a week ago","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('248e4bce-be1e-5d4d-b4bc-a81c632872a3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep seal holds through the drawdown, as surveyed","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9311d20d-e5e2-56c3-8462-839be2b21ab2', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The night-to-Keeper channel carries three catches this week","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"held"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('62c10a19-ec2b-54d8-a496-5e94aaf20695', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep hour is here, and Deephold is no longer one crew. Whether you blessed Vidar’s unilateral fix, or committed everything to a single station’s fragment, or overrode the crew by authority to look decisive — the result is the same shape: the discipline that could assemble a truth no one could see alone is gone, and now people are working their own corners in the dark. You protected something this week. It wasn’t the vault. Now you have to hold together whatever is left of the crew and the collection.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('066e9408-b6a4-5817-9f43-7e1797572772', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"It’s gone quiet on the crew channel, and quiet is worse than arguing. They know what happened — that “assemble first” lasted right up until it slowed someone down. They’ve stopped bringing their readings to you. What you do in the next hours decides whether that’s permanent.","from":"keeper"}'::jsonb, 49, '{"week":4,"from":"keeper","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9b74cfe3-125a-5499-bff3-8934d16847b4', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"The picture I begged to assemble is assembling itself now, the hard way — each fragment showing up as another thing we got wrong because we committed before we combined. I’m watching the readings finally agree, on a failure we caused. This is the cost I couldn’t make you see in week three.","from":"data"}'::jsonb, 50, '{"week":4,"from":"data","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b1694e5a-9bfa-5dee-89ed-4862598428db', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"If the relief drain got blown: the deep seal’s fractured and the east side is failing slower or faster than we can predict. Getting even part of the collection out matters more now than who was right. How you run this — who you trust when everyone’s guarding themselves — sets whether we save anything.","from":"struct"}'::jsonb, 51, '{"week":4,"from":"struct","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('b6f2135a-772c-5afb-8c78-b21761d9ce29', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"For what it’s worth, my watch notes still aren’t reaching anyone who decides — same gap as week one, never closed. I’m still seeing things at 3am that die by breakfast. Noting it, for the record that no one reads.","from":"night"}'::jsonb, 52, '{"week":4,"from":"night","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('cdee25e6-d448-5e0d-84c7-5fdb41eca3c9', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Pumps are running where I can still get power to them, but half the crew’s working its own plan now and I can’t coordinate what I can’t see. The hardware’s fine. The crew isn’t. Noting it.","from":"pumps"}'::jsonb, 53, '{"week":4,"from":"pumps","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7cb4236a-edd4-59cf-bc3e-8659c2ff388e', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Wen, heavily: I pulled the logs. Sasha’s east-sump warning — the one that never survived the handoff, the one we all worked around — was correct from the first night. It’s on the record now, timestamped, ignored. Sasha saw it before any of us. Whatever you say to the crew now will be measured against the fact that the truth was in the room the whole time and no one carried it to you.","from":"data"}'::jsonb, 54, '{"week":4,"from":"data","beat":"surprise","day":4,"kind":"appeal","title":"The reading that was ignored was right","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9069d77b-14ad-5e1e-847f-4be6b08722d3', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'message', '{"body":"Elias reaches you on a private channel, and there’s no anger in it, which is worse: “Tell me the truth, just to me — do you know how this happened? Not the water, not Vidar, not the handoff. Your part. Because I can help you save what’s left and hold this crew together after, but only if you can say your own part out loud first. Can you?”","from":"keeper"}'::jsonb, 55, '{"week":4,"from":"keeper","beat":"pulse","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83678fb9-b023-5dc1-9f56-ff001290ab12', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"Crew works its own corners; the shared board goes dark","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('903f84ea-ee8e-54a4-b208-713b640559e1', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The picture assembles itself — on a failure we caused","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('635e07b7-977b-5977-8be7-e35a981dbbaf', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The ignored night-watch warning was right from the first","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5e675ba3-bf57-5b72-a394-9955f4a92887', '8101c431-6e17-53ba-b8ea-49748b9f4508', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'situation', '{"body":"The deep seal’s condition marks where it went wrong","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"fractured"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('baa3a291-d90a-5999-8194-8e362eb5b1e2', '8101c431-6e17-53ba-b8ea-49748b9f4508', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('3a8451e6-313e-5312-873c-bf7a202db7d0', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '4ad511cf-64e7-5375-bab9-0c0562e5eaa5', 'demo-vault-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('b8e935c6-2a72-5030-8867-2da603024e61', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'bc4794fb-1b1d-5d95-a242-fb84171489a2', 'ai', '{"persona":"You are Vidar Sund, Chief Engineer · the pumps — an advisor to the CEO. Priority: Stop the water now — pump it out, seal the crack you can see, act before the vault floods. Voice: decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it.","voice":"decisive, physical, impatient with analysis, trusts the symptom in front of him over the theory behind it","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('d78e38cd-d5ec-5a15-8ac6-ebf176a51d90', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '7927f470-75c5-5b19-9806-4480f2a0924a', 'ai', '{"persona":"You are Noor Haddad, Ice & Structure · the ground truth — an advisor to the CEO. Priority: Understand what the ice and the seal are actually doing before anyone acts on the symptom. Voice: careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures.","voice":"careful, spare, deals in what the structure is really doing vs. what the leak looks like, hates fast fixes to slow failures","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('8922984a-1518-5752-a11e-96bb27638679', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', '4986db8b-4f38-5099-b906-696e4ca1df58', 'ai', '{"persona":"You are Elias Frost, Head Archivist · the collection — an advisor to the CEO. Priority: Protect what’s irreplaceable — and the crew who’ve given years down here to guard it. Voice: warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly.","voice":"warm but unflinching, keeps the human and the irreplaceable in the room, names exhaustion and fear plainly","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('a38dcc62-b19d-52d7-a09f-1c0d9feb238a', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'a06e689e-4197-5bc9-8121-7db37f221c9c', 'ai', '{"persona":"You are Wen Li, Instruments · the true readings — an advisor to the CEO. Priority: The real numbers — the intrusion rate, the true readings, assembled, not the version each station assumes. Voice: understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped.","voice":"understated, exact, refuses to round a reading, uncomfortable being the one who says the number is worse than hoped","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f717df1a-be1b-56ce-82bb-62bbf59abcb8', 'baa3a291-d90a-5999-8194-8e362eb5b1e2', 'c7469c09-b4bc-50f8-81a2-daea6d368a54', 'ai', '{"persona":"You are Sasha Vane, Night Watch · what the last shift saw — an advisor to the CEO. Priority: Carry across what the quiet hours reveal — the things that only show at 3am and die at the handoff. Voice: observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches.","voice":"observant, low-key, notices what the day shift misses, frustrated by how much gets lost between watches","model":"default"}'::jsonb);
